import{_ as t,o as n,c as i,a0 as o}from"./chunks/framework.CWk8AOcY.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),a={name:"guide/introduction.md"};function r(s,e,l,d,c,u){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Welcome to the Cube Security Sandbox documentation.</p><p>Cube Sandbox is a production-grade, multi-component security sandbox system designed for serverless computing and secure code execution environments. It implements a VM-based container isolation architecture using KVM hypervisor technology.</p><h2 id="key-advantages" tabindex="-1">Key Advantages <a class="header-anchor" href="#key-advantages" aria-label="Permalink to &quot;Key Advantages&quot;">​</a></h2><ul><li><p><strong>Exceptional Performance</strong>: Fully optimized end-to-end for sandbox workloads. Delivers each sandbox instance in under 100ms with less than 5MB of additional memory overhead — even at 100 concurrent sandboxes on a single machine.</p></li><li><p><strong>Secure by Design</strong>: Hardware-level isolation combined with comprehensive network security policies, enforcing strict security boundaries between sandbox instances in multi-tenant environments.</p></li><li><p><strong>Ready Out of the Box</strong>: No complex dependencies. A minimal deployment script gets a Cube Sandbox environment running locally in minutes, letting you experience its core capabilities immediately.</p></li><li><p><strong>E2B Compatible</strong>: Drop-in compatible with the E2B sandbox protocol — existing Agent applications and workflows gain significantly stronger security without any business logic changes.</p></li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./quickstart.html">Quick Start</a> — the fastest path from zero to a running sandbox.</li><li><a href="./self-build-deploy.html">Self-Build Deployment</a> — single-machine deployment reference with prerequisites, configuration, and troubleshooting.</li><li><a href="./multi-node-deploy.html">Multi-Node Cluster Deployment</a> — add compute nodes to scale beyond a single machine.</li><li><a href="./tutorials/template-from-image.html">Creating Templates from OCI Images</a> — step-by-step CLI guide for template creation, monitoring, and management.</li></ul>',7)])])}const h=t(a,[["render",r]]);export{p as __pageData,h as default};
